class Solution {
public:
    int primePalindrome(int n) {
        while (true) {
            if (isPalindrome(n) && isPrime(n)) return n;
            n++;
            if (n > 100000000 && n != reverseNum(n)) n = nextPalindrome(n);
        }
    }

    bool isPrime(int n) {
        if (n <= 1) return false;
        if (n <= 3) return true;
        if (n % 2 == 0 || n % 3 == 0) return false;
        for (int i = 5; i * i <= n; i += 6)
            if (n % i == 0 || n % (i + 2) == 0) return false;
        return true;
    }

    bool isPalindrome(int n) {
        int reversed = reverseNum(n);
        return n == reversed;
    }

    int reverseNum(int n) {
        int reversed = 0;
        while (n > 0) {
            reversed = reversed * 10 + n % 10;
            n /= 10;
        }
        return reversed;
    }

    int nextPalindrome(int n) {
        string str = to_string(n);
        int len = str.length();
        if (len % 2 == 0) {
            string firstHalf = str.substr(0, len / 2);
            string newFirstHalf = to_string(stoi(firstHalf) + 1);
            if (newFirstHalf.length() > firstHalf.length()) {
                return stoi(newFirstHalf + string(newFirstHalf.rbegin(), newFirstHalf.rend()));
            } else {
                return stoi(newFirstHalf + newFirstHalf.substr(0, len / 2));
            }
        } else {
            string firstHalf = str.substr(0, (len + 1) / 2);
            string newFirstHalf = to_string(stoi(firstHalf) + 1);
            if (newFirstHalf.length() > firstHalf.length()) {
                return stoi(newFirstHalf + string(newFirstHalf.rbegin() + 1, newFirstHalf.rend()));
            } else {
                return stoi(newFirstHalf + newFirstHalf.substr(0, (len + 1) / 2 - 1));
            }
        }
    }
};
